mapper.select:
SELECT id, trace_id AS traceId, span_id AS spanId, request_uri AS requestUri, http_method_type AS httpMethodType, request_header AS requestHeader, request_param AS requestParam, request_body AS requestBody, response_status AS responseStatus, response_body AS responseBody, process_time AS processTime, created_at AS createdAt, created_by AS createdBy FROM tb_api_log
AND id = #{id}
AND trace_id = #{traceId}
AND span_id = #{spanId}
AND request_uri ILIKE CONCAT('%', #{requestUri}, '%')
AND http_method_type = #{httpMethodType}
AND request_header ILIKE CONCAT('%', #{requestHeader}, '%')
AND request_param ILIKE CONCAT('%', #{requestParam}, '%')
AND request_body ILIKE CONCAT('%', #{requestBody}, '%')
AND response_status = #{responseStatus}
AND response_body ILIKE CONCAT('%', #{responseBody}, '%')
AND created_at >= #{createdAtFrom}
AND created_at < #{createdAtToExclusive}
